    if (speed > 255) speed = 255;

    gpioPWM(FAN_GPIO, speed * (PWM_RANGE / 255.0));
}

// Function to update the circular buffer
void update_circular_buffer(float temperature, int pwm_duty_cycle) {
    time(&buffer[buffer_index].timestamp);
    buffer[buffer_index].temperature = temperature;
    buffer[buffer_index].pwm_duty_cycle = pwm_duty_cycle;

    buffer_index = (buffer_index + 1) % NUM_ENTRIES;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Received signal %d, terminating...\n", signal);
    terminate = 1;
}

// Function to map a value from one range to another
int map_range(float input_min, float input_max, float output_min, float output_max, float value) {
    return (int)(output_min + (value - input_min) * (output_max - output_min) / (input_max - input_min));
}

