#define BUZZER_2_PIN 18
#define BUZZER_3_PIN 22

// Define alarm thresholds
#define WARNING_THRESHOLD 20
#define CRITICAL_THRESHOLD 10

// Define alarm frequencies and durations (Hz and seconds)
#define WARNING_FREQUENCY 500
#define CRITICAL_FREQUENCY 1000
#define WARNING_ON_DURATION 0.2
#define WARNING_OFF_DURATION 0.5

// Global flag for graceful shutdown
volatile sig_atomic_t program_running = 1;

// Signal handler for Ctrl+C
void signal_handler(int signal) {
    program_running = 0;
    fprintf(stderr, "\nCaught signal %d, stopping program...\n", signal);
}

// Function to set buzzer frequency and duty cycle
void set_buzzer(int pin, int frequency, int duty_cycle) {
    if (frequency == 0) {
        gpioWrite(pin, 0); // Turn off buzzer
    } else {
        int range = 1000000 / frequency; // Calculate PWM range for desired frequency
        int actual_duty_cycle = range * duty_cycle / 255; // Scale duty cycle to the calculated range

        gpioSetPWMfrequency(pin, frequency);
        gpioPWM(pin, actual_duty_cycle); // Set duty cycle
    }
}

// Function to trigger warning alarm pattern
void warning_alarm(int pin) {
    set_buzzer(pin, WARNING_FREQUENCY, 128); // 50% duty cycle
    gpioDelay(WARNING_ON_DURATION * 1000000); // Convert seconds to microseconds
    set_buzzer(pin, 0, 0); // Turn off buzzer
    gpioDelay(WARNING_OFF_DURATION * 1000000); // Convert seconds to microseconds
}

// Function to trigger critical alarm pattern
void critical_alarm(int pin) {
    set_buzzer(pin, CRITICAL_FREQUENCY, 128); // 50% duty cycle
}

// Function to process sensor data and control the buzzer
void process_sensor_data(int pin, int distance) {
    if (distance < CRITICAL_THRESHOLD) {
        critical_alarm(pin);
    } else if (distance < WARNING_THRESHOLD) {
        warning_alarm(pin);
    } else {
        set_buzzer(pin, 0, 0); // Turn off buzzer
    }
}

int main() {
    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pins to output mode
    gpioSetMode(BUZZER_1_PIN, PI_OUTPUT);
    gpioSetMode(BUZZER_2_PIN, PI_OUTPUT);
    gpioSetMode(BUZZER_3_PIN, PI_OUTPUT);

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Main loop to read sensor data and control buzzers
    char line[256];
    int distance1, distance2, distance3;

    fprintf(stdout, "Aircraft Proximity Alert System started. Press Ctrl+C to exit.\n");

    while (program_running) {
        if (fgets(line, sizeof(line), stdin) != NULL) {
            // Parse sensor data from input line
            if (sscanf(line, "%d %d %d", &distance1, &distance2, &distance3) == 3) {
                // Process sensor data and control buzzers
                process_sensor_data(BUZZER_1_PIN, distance1);
                process_sensor_data(BUZZER_2_PIN, distance2);
                process_sensor_data(BUZZER_3_PIN, distance3);
            } else {
                fprintf(stderr, "Invalid input format. Please provide three integer values separated by spaces.\n");
            }
        } else {
            // Error reading from stdin or end of input
            if (ferror(stdin)) {
                fprintf(stderr, "Error reading from stdin\n");
            }
            break; // Exit loop on error or EOF
        }
    }

    // Stop all buzzers and terminate pigpio library before exiting
    set_buzzer(BUZZER_1_PIN, 0, 0);
    set_buzzer(BUZZER_2_PIN, 0, 0);
    set_buzzer(BUZZER_3_PIN, 0, 0);

    gpioTerminate();

    fprintf(stdout, "Aircraft Proximity Alert System stopped.\n");

    return 0;
