// Function to read a single byte from an Si1153 register
int si1153_read_register(int fd, int reg) {
    int result = wiringPiI2CReadReg8(fd, reg);
    if (result == -1) {
        perror("Error reading from I2C device");
        return -1; // Indicate error
    }
    return result;
}

// Function to write a single byte to an Si1153 register
int si1153_write_register(int fd, int reg, int value) {
    int result = wiringPiI2CWriteReg8(fd, reg, value);
    if (result == -1) {
        perror("Error writing to I2C device");
        return -1; // Indicate error
    }
    return 0; // Indicate success
}

// Function to read proximity, ambient light, and UV index data from the sensor
int read_sensor_data(int fd, unsigned short *proximity, unsigned short *ambient_light, unsigned short *uv_index) {
    int proximity_low, proximity_high;
    int ambient_low, ambient_high;
    int uv_low, uv_high;

    proximity_low = si1153_read_register(fd, SI1153_REG_PS1_DATA0);
    proximity_high = si1153_read_register(fd, SI1153_REG_PS1_DATA0 + 1);

    ambient_low = si1153_read_register(fd, SI1153_REG_ALS_VIS_DATA0);
    ambient_high = si1153_read_register(fd, SI1153_REG_ALS_VIS_DATA0 + 1);

    uv_low = si1153_read_register(fd, SI1153_REG_UVINDEX_DATA0);
    uv_high = 0; // UV index is usually just one byte

    if (proximity_low == -1 || proximity_high == -1 || ambient_low == -1 || ambient_high == -1 || uv_low == -1) {
        return -1; // Indicate error
    }

    *proximity = (unsigned short)((proximity_high << 8) | proximity_low);
    *ambient_light = (unsigned short)((ambient_high << 8) | ambient_low);
    *uv_index = (unsigned short)(uv_low); // UV index is typically one byte

    return 0; // Indicate success
}

