    signal(SIGTERM, signal_handler);

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Initialize I2C
    if (init_i2c() != 0) {
        cleanup();
        return 1;
    }

    // Initialize GPIO
    if (init_gpio() != 0) {
        cleanup();
        return 1;
    }

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        cleanup();
        return 1;
